#include <stdio.h>
#include <stdlib.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long a,b;
        scanf("%lld %lld",&a,&b);
        printf("%lld\n", a/b);
    }
    return 0;
}

